def forward(self, x):
        assert x.shape[1] == self.channels
        if self.use_conv_transpose:
            return self.conv(x)

        if self.dims == 3:
            x = F.interpolate(x, (x.shape[2], x.shape[3] * 2, x.shape[4] * 2), mode="nearest")
        else:
            x = F.interpolate(x, scale_factor=2.0, mode="nearest")

        if self.use_conv:
            x = self.conv(x)

        return x

def pack_ext_type(self, typecode, data):
        if not isinstance(typecode, int):
            raise TypeError("typecode must have int type.")
        if not 0 <= typecode <= 127:
            raise ValueError("typecode should be 0-127")
        if not isinstance(data, bytes):
            raise TypeError("data must have bytes type")
        L = len(data)
        if L > 0xFFFFFFFF:
            raise ValueError("Too large data")
        if L == 1:
            self._buffer.write(b"\xd4")
        elif L == 2:
            self._buffer.write(b"\xd5")
        elif L == 4:
            self._buffer.write(b"\xd6")
        elif L == 8:
            self._buffer.write(b"\xd7")
        elif L == 16:
            self._buffer.write(b"\xd8")
        elif L <= 0xFF:
            self._buffer.write(b"\xc7" + struct.pack("B", L))
        elif L <= 0xFFFF:
            self._buffer.write(b"\xc8" + struct.pack(">H", L))
        else:
            self._buffer.write(b"\xc9" + struct.pack(">I", L))
        self._buffer.write(struct.pack("B", typecode))
        self._buffer.write(data)

def reconstruction_error(S1, S2, reduction='mean'):

    S1_hat = compute_similarity_transform_batch(S1, S2)
    re = np.sqrt(((S1_hat - S2)**2).sum(axis=-1)).mean(axis=-1)
    if reduction == 'mean':
        re = re.mean()
    elif reduction == 'sum':
        re = re.sum()
    return re

def get_instance(cls, info, **data):
        object_id = data.get("id")
        qs = data.get("qs", None)

        try:
            type_name, _ = from_global_id_or_error(object_id)
            if type_name == "Order":
                raise ValidationError(
                    {
                        "id": ValidationError(
                            "Changing order metadata with `Order.id` is forbidden. "
                            "Use `Order.token` as an identifier instead.",
                            code=MetadataErrorCode.GRAPHQL_ERROR.value,
                        )
                    }
                )
            # ShippingMethodType represents the ShippingMethod model
            if type_name == "ShippingMethodType":
                qs = shipping_models.ShippingMethod.objects
            return cls.get_node_or_error(info, object_id, qs=qs)
        except GraphQLError as e:
            if instance := cls.get_instance_by_token(object_id, qs):
                return instance
            raise ValidationError(
                {
                    "id": ValidationError(
                        str(e), code=MetadataErrorCode.GRAPHQL_ERROR.value
                    )
                }
            )

def __getstate__(self):
        state = self.__dict__.copy()
        if "fields_cache" in state:
            state["fields_cache"] = self.fields_cache.copy()
        # Manager instances stored in related_managers_cache won't necessarily
        # be deserializable if they were dynamically created via an inner
        # scope, e.g. create_forward_many_to_many_manager() and
        # create_generic_related_manager().
        if "related_managers_cache" in state:
            state["related_managers_cache"] = {}
        return state

