def copy2_fixed(src, dest):
        # type: (str, str) -> None

        try:
            shutil.copy2(src, dest)
        except OSError:
            for f in [src, dest]:
                try:
                    is_socket_file = is_socket(f)
                except OSError:
                    # An error has already occurred. Another error here is not
                    # a problem and we can ignore it.
                    pass
                else:
                    if is_socket_file:
                        raise shutil.SpecialFileError(
                            "`{f}` is a socket".format(**locals())
                        )

            raise

def copyfile(src, dst):

    if _samefile(src, dst):
        raise Error("`%s` and `%s` are the same file" % (src, dst))

    for fn in [src, dst]:
        try:
            st = os.stat(fn)
        except OSError:
            # File most likely does not exist
            pass
        else:
            # XXX What about other special files? (sockets, devices...)
            if stat.S_ISFIFO(st.st_mode):
                raise SpecialFileError("`%s` is a named pipe" % fn)

    with open(src, 'rb') as fsrc:
        with open(dst, 'wb') as fdst:
            copyfileobj(fsrc, fdst)

def _proc_gnusparse_00(self, next, pax_headers, buf):

        offsets = []
        for match in re.finditer(br"\d+ GNU.sparse.offset=(\d+)\n", buf):
            offsets.append(int(match.group(1)))
        numbytes = []
        for match in re.finditer(br"\d+ GNU.sparse.numbytes=(\d+)\n", buf):
            numbytes.append(int(match.group(1)))
        next.sparse = list(zip(offsets, numbytes))

def _check_buffer(self) -> None:

        if self.quiet:
            del self._buffer[:]
            return
        with self._lock:
            if self._buffer_index == 0:

                if self.record:
                    with self._record_buffer_lock:
                        self._record_buffer.extend(self._buffer[:])

                if self.is_jupyter:  # pragma: no cover
                    from .jupyter import display

                    display(self._buffer, self._render_buffer(self._buffer[:]))
                    del self._buffer[:]
                else:
                    if WINDOWS:
                        use_legacy_windows_render = False
                        if self.legacy_windows:
                            try:
                                use_legacy_windows_render = (
                                    self.file.fileno() in _STD_STREAMS
                                )
                            except (ValueError, io.UnsupportedOperation):
                                pass

                        if use_legacy_windows_render:
                            from pipenv.patched.notpip._vendor.rich._win32_console import LegacyWindowsTerm
                            from pipenv.patched.notpip._vendor.rich._windows_renderer import legacy_windows_render

                            legacy_windows_render(
                                self._buffer[:], LegacyWindowsTerm(self.file)
                            )
                        else:
                            # Either a non-std stream on legacy Windows, or modern Windows.
                            text = self._render_buffer(self._buffer[:])
                            # https://bugs.python.org/issue37871
                            write = self.file.write
                            for line in text.splitlines(True):
                                try:
                                    write(line)
                                except UnicodeEncodeError as error:
                                    error.reason = f"{error.reason}\n*** You may need to add PYTHONIOENCODING=utf-8 to your environment ***"
                                    raise
                    else:
                        text = self._render_buffer(self._buffer[:])
                        try:
                            self.file.write(text)
                        except UnicodeEncodeError as error:
                            error.reason = f"{error.reason}\n*** You may need to add PYTHONIOENCODING=utf-8 to your environment ***"
                            raise

                    self.file.flush()
                    del self._buffer[:]

