def zeroVector(dimension):

    # precondition
    assert isinstance(dimension, int)
    ans = []
    for i in range(dimension):
        ans.append(0)
    return Vector(ans)

def __sub__(self, other):

        size = self.size()
        result = []
        if size == other.size():
            for i in range(size):
                result.append(self.__components[i] - other.component(i))
        else:  # error case
            raise Exception("must have the same size")
        return Vector(result)

def squareZeroMatrix(N):

    ans = []
    for i in range(N):
        row = []
        for j in range(N):
            row.append(0)
        ans.append(row)
    return Matrix(ans, N, N)

def __add__(self, other):

        size = self.size()
        result = []
        if size == other.size():
            for i in range(size):
                result.append(self.__components[i] + other.component(i))
        else:
            raise Exception("must have the same size")
        return Vector(result)

def randomMatrix(W, H, a, b):

    matrix = []
    random.seed(None)
    for i in range(H):
        row = []
        for j in range(W):
            row.append(random.randint(a, b))
        matrix.append(row)
    return Matrix(matrix, W, H)

def __mul__(self, other):

        ans = []
        if isinstance(other, float) or isinstance(other, int):
            for c in self.__components:
                ans.append(c * other)
        elif isinstance(other, Vector) and (self.size() == other.size()):
            size = self.size()
            summe = 0
            for i in range(size):
                summe += self.__components[i] * other.component(i)
            return summe
        else:  # error case
            raise Exception("invalide operand!")
        return Vector(ans)

def sieveEr(N):

    from math import sqrt

    # precondition
    assert isinstance(N, int) and (N > 2), "'N' must been an int and > 2"

    primes = [True for x in range(N + 1)]

    for p in range(2, int(sqrt(N)) + 1):
        if primes[p]:
            for i in range(p * p, N + 1, p):
                primes[i] = False
    primes[0] = False
    primes[1] = False
    ret = []
    for p in range(N + 1):
        if primes[p]:
            ret.append(p)

    return ret


