def _request(self, method, path, **kwargs):
        self._ensure_open()

        url = urljoin(self.url, path)

        # required for load balancing
        kwargs.setdefault("headers", {})["x-sentry-project-id"] = self.project_id
        kwargs.setdefault("headers", {})["x-sentry-event-id"] = self.event_id
        kwargs.setdefault("headers", {})["x-sentry-worker-id"] = self.get_worker_id()

        attempts = 0
        wait = 0.5

        while True:
            try:
                with metrics.timer(
                    "events.symbolicator.session.request", tags={"attempt": attempts}
                ):
                    response = self.session.request(
                        method, url, timeout=settings.SYMBOLICATOR_POLL_TIMEOUT + 1, **kwargs
                    )

                metrics.incr(
                    "events.symbolicator.status_code",
                    tags={"status_code": response.status_code, "project_id": self.project_id},
                )

                if (
                    method.lower() == "get"
                    and path.startswith("requests/")
                    and response.status_code == 404
                ):
                    # The symbolicator does not know this task. This is
                    # expected to happen when we're currently deploying
                    # symbolicator (which will clear all of its state). Re-send
                    # the symbolication task.
                    return None

                if response.status_code in (502, 503):
                    raise ServiceUnavailable()

                if response.ok:
                    json = response.json()
                else:
                    with sentry_sdk.push_scope():
                        sentry_sdk.set_extra("symbolicator_response", response.text)
                        sentry_sdk.capture_message("Symbolicator request failed")

                    json = {"status": "failed", "message": "internal server error"}

                return self._process_response(json)
            except (OSError, RequestException) as e:
                metrics.incr(
                    "events.symbolicator.request_error",
                    tags={
                        "exc": ".".join([e.__class__.__module__, e.__class__.__name__]),
                        "attempt": attempts,
                    },
                )

                attempts += 1
                # Any server error needs to be treated as a failure. We can
                # retry a couple of times, but ultimately need to bail out.
                #
                # This can happen for any network failure.
                if attempts > MAX_ATTEMPTS:
                    logger.error("Failed to contact symbolicator", exc_info=True)
                    raise

                time.sleep(wait)
                wait *= 2.0

def do_gc():
    stable_window_tags = []
    for repo in repos(client):
        repositoryName = repo["repositoryName"]
        if not repositoryName.startswith(args.filter_prefix):
            continue

        # Keep list of image digests to delete for this repository
        digest_to_delete = []

        for image in images(client, repo):
            tags = image.get("imageTags")
            if not isinstance(tags, (list,)) or len(tags) == 0:
                continue
            created = image["imagePushedAt"]
            age = now - created
            for tag in tags:
                if any([
                        looks_like_git_sha(tag),
                        tag.isdigit(),
                        tag.count("-") == 4,  # TODO: Remove, this no longer applies as tags are now built using a SHA1
                        tag in ignore_tags]):
                    window = stable_window
                    if tag in ignore_tags:
                        stable_window_tags.append((repositoryName, tag, "", age, created))
                    elif age < window:
                        stable_window_tags.append((repositoryName, tag, window, age, created))
                else:
                    window = unstable_window

                if tag in ignore_tags or age < window:
                    if args.debug:
                        print("Ignoring {}:{} (age: {})".format(repositoryName, tag, age))
                    break
            else:
                for tag in tags:
                    print("{}Deleting {}:{} (age: {})".format("(dry run) " if args.dry_run else "", repositoryName, tag, age))
                digest_to_delete.append(image["imageDigest"])
        if args.dry_run:
            if args.debug:
                print("Skipping actual deletion, moving on...")
        else:
            # Issue batch delete for all images to delete for this repository
            # Note that as of 2018-07-25, the maximum number of images you can
            # delete in a single batch is 100, so chunk our list into batches of
            # 100
            for c in chunks(digest_to_delete, 100):
                client.batch_delete_image(
                    registryId="308535385114",
                    repositoryName=repositoryName,
                    imageIds=[{"imageDigest": digest} for digest in c],
                )

            save_to_s3(args.filter_prefix, stable_window_tags)


